const Q_PHYSICS_2014=[{"id": "objective>Physics>2014>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What subject is this?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Physics</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Chemistry</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mathematics</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Biology</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The subject is Physics. This can be inferred from the question id which contains the word 'Physics'.</div>", "topic": "INTRODUCTION"}, {"id": "objective>Physics>2014>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is the least possible error encountered when taking measurement with a meter rule?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.5mm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.2mm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.1 mm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.0 mm</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Note that the error in any measurement is given as half of the smallest scale division (accuracy) <br/> The accuracy of a metre rule is 1.0mm <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">∴</td><td style=\"text-align:center;\">The</td><td style=\"text-align:center;\">uncertainty</td><td style=\"text-align:center;\">(error)</td><td style=\"text-align:center;\">in</td><td style=\"text-align:center;\">any</td><td style=\"text-align:center;\">measurement</td><td style=\"text-align:center;\">involving</td><td style=\"text-align:center;\">a</td><td style=\"text-align:center;\">metre</td><td style=\"text-align:center;\">rule</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">(1.0mm)</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.5mm</td></tr></table></div></div>", "topic": "MEASUREMENTS AND UNITS : LIMITATIONS OF EXPERIMENTAL MEASUREMENTS"}, {"id": "objective>Physics>2014>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A quantity which requires magnitude and direction to be specified is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">displacement</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mass</div>", "<div style=\"font-family:Cambria;font-size:17px;\">temperature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">distance</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A quantity which has both magnitude and direction associated with it is a vector quantity. <br/> Note that in the options given, only displacement is a vector quantity. Mass, temperature and distance are scalar quantity.</div>", "topic": "SCALARS AND VECTORS"}, {"id": "objective>Physics>2014>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">I. Electrical potential  <br/> II. Torque   <br/> III. Kinetic energy   <br/>  <br/> IV. Momentum   <br/> Which of the quantities listed above are vectors?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I and III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II and III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II and IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and II</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Vector quantities are quantities that have both magnitude and direction. Among the options given, Torque (II) and Momentum (IV) are vector quantities because they both have magnitude and direction. Electrical potential (I) and Kinetic energy (III) are scalar quantities because they only have magnitude and no direction.</div>", "topic": "SCALARS AND VECTORS"}, {"id": "objective>Physics>2014>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which type of motion do the wheels of a moving car undergo?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Rotational and oscillatory motion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Translational and rotational motion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Vibratory and translational motion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Random and translational motion</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The wheels of a moving car undergo both translational and rotational motion. Translational motion refers to the movement of an object from one point to another in a straight or curved path, while rotational motion refers to the movement of an object around an axis. In the case of a moving car, the car itself moves from one point to another (translational motion), while its wheels rotate around their axes (rotational motion).</div>", "topic": "MOTION: TYPES OF MOTION"}, {"id": "objective>Physics>2014>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/> From the diagram above, the region of zero acceleration is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">NS</div>", "<div style=\"font-family:Cambria;font-size:17px;\">SP</div>", "<div style=\"font-family:Cambria;font-size:17px;\">PQ</div>", "<div style=\"font-family:Cambria;font-size:17px;\">MX</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Recall:</td><td style=\"text-align:center;\">acceleration</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Increase in velocity<hr size=\"1\" />Time</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">ΔV<hr size=\"1\" />t</td></tr></table></div> <br/> At point NS, the body has a constant velocity, i.e  <br/> ΔV = 0 <br/> a = ΔV/t = 0/t = 0 <br/> ∴ At NS, acceleration is zero.</div>", "topic": "MOTION: LINEAR MOTION"}, {"id": "objective>Physics>2014>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A car accelerates uniformly from rest at 3ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>, its velocity after travelling a distance of 24m is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">72ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">36ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">12 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">144 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Initial velocity, U = o {from rest} <br/> Acceleration, a = 3ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> <br/> Distance, S = 24m <br/> Final velocity, V = ? <br/> Recall: v<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = u<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> + 2as <br/> V<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = 0<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> + 2(3)(24) <br/> V<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = 144 <br/> V = 12.0m/s</div>", "topic": "MOTION: LINEAR MOTION"}, {"id": "objective>Physics>2014>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Calculate the escape velocity of a satellite launched from the earth's surface if the radius of the earth is 6.4x l0<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>m. <br/>  [g = 10 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4.0 kms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">11.3 kms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">25.3 kms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.2 kms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>\t</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Radius of the earth, R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span> = 6.4 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>r <br/> <img src=\"2014/1.png\" style=\"position:relative;max-width:100%;\"/> <br/> Recall: V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span> (escape velocity) = &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">2gR<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span>&nbsp;</span> <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span> = &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">2 × 10 × 6.4 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>&nbsp;</span> = &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">128&nbsp;</span> × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span> = 11.3km/s</div>", "topic": "GRAVITATIONAL FIELD : ESCAPE VELOCITY"}, {"id": "objective>Physics>2014>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An object of mass 8 kg on earth is taken to a planet where the acceleration due to gravity is one-third of its value on earth. <br/>   <br/> The weight of the object on the planet is  <br/>   <br/> [g = 10 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">27N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">36N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">48N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">12N</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Mass on the earth, m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span> = 8kg <br/> Weight on the earth, W<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span> = m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span>g = 8 × 10 = 80N <br/> Mass of the planet = mass on the earth = 8kg <br/> Weight on the planet = 8 × g<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">N.B:</td><td style=\"text-align:center;\">g<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />3</td><td style=\"text-align:center;\">g<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">W<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">8</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">1<hr size=\"1\" />3</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">10</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">80<hr size=\"1\" />3</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">26.67N</td><td style=\"text-align:center;\">≈</td><td style=\"text-align:center;\">27N</td></tr></table></div></div>", "topic": "GRAVITATIONAL FIELD"}, {"id": "objective>Physics>2014>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the conditions necessary for an object to be in equilibrium when acted upon by a number of parallel forces is that the vector sum of the forces is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">negative</div>", "<div style=\"font-family:Cambria;font-size:17px;\">positive</div>", "<div style=\"font-family:Cambria;font-size:17px;\">average</div>", "<div style=\"font-family:Cambria;font-size:17px;\">zero</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">For an object to be in equilibrium when acted upon by several parallel force, the vector sum of the forces must be zero.</div>", "topic": "EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES"}, {"id": "objective>Physics>2014>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What happens when three coplanar non-parallel forces are in equilibrium?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">They are represented in direction only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Their lines of action meet at a point</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Their lines of action are parallel</div>", "<div style=\"font-family:Cambria;font-size:17px;\">They are represented in magnitude only</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When three coplanar non-parallel forces are in equilibrium, their lines of action meet at a point. This is known as the principle of moments or the principle of torques. It states that for a system to be in equilibrium, the sum of the clockwise moments about any point must be equal to the sum of the anticlockwise moments about the same point. If the lines of action of the forces do not meet at a point, it would create a moment or torque, causing the object to rotate.</div>", "topic": "EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES"}, {"id": "objective>Physics>2014>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An object of mass 20kg is released from a height of 10 m above the ground level.  <br/> The kinetic energy of the object just before it hits the ground is ..... <br/>  [g = 10 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2000J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">500J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">200J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4000J</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The kinetic energy of the object just before hitting the ground is the same as its potential energy = mgh = 20 × 10 × 10 = 2000J.</div>", "topic": "WORK ENERGY AND POWER : CONSERVATION OF ENERGY"}, {"id": "objective>Physics>2014>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The energy in the nucleus of atoms produce heat which can be used to generate</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">electrical energy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">potential energy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">kinetic energy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mechanical energy</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The energy in the nucleus of atoms is typically harnessed in nuclear power plants to produce heat. This heat is then used to generate steam which drives a turbine connected to a generator, thus producing electrical energy. Therefore, the correct answer is 'electrical energy'.</div>", "topic": "ELEMENTARY MODERN PHYSICS : FUSION AND FISSION"}, {"id": "objective>Physics>2014>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A machine whose efficiency is 75% is used to lift a load of 1000N. <br/>   <br/> Calculate the effort put in to the machine if it has a velocity ratio of 4.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">333.33 N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">334.33 N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">343.32 N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">233.33 N</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given <br/> Efficienct, E = 75% <br/> Load, L = 1000N <br/> Velocity Ratio, V.R = 4.0 <br/> Effort, E = ? <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Recall:</td><td style=\"text-align:center;\">E</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">M.A<hr size=\"1\" />V.R</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100</td><td style=\"text-align:center;\">----------------</td><td style=\"text-align:center;\">(1)</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">M.A</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Load<hr size=\"1\" />Effort</td><td style=\"text-align:center;\">--------------------</td><td style=\"text-align:center;\">(2)</td></tr></table></div> <br/> From (1) <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">75</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">M.A<hr size=\"1\" />4</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100</td></tr></table></div> <br/> M.A = 3.0 <br/> From (2) <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">3</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1000<hr size=\"1\" />Effort</td></tr></table></div> <br/> Effort, E = 333.33N</div>", "topic": "SIMPLE MACHINES : EFFICIENCY OF MACHINES"}, {"id": "objective>Physics>2014>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A wheel and axle is used to raise a load whose weight is 800N when an effort of 250N is applied. If the radii of the wheel and axle are 800mm and 200mm respectively, the efficiency of the machine is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">85%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">87%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">90%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">80%</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Load, L = 800N <br/> Effort, E = 250N <br/> Radii of wheel, R = 800mm <br/> Radii of axle, r = 200mm <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Efficiency</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">M.A<hr size=\"1\" />V.R</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100</td><td style=\"text-align:center;\">-------------</td><td style=\"text-align:center;\">(1)</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">M.A</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">L<hr size=\"1\" />E</td><td style=\"text-align:center;\">--------------</td><td style=\"text-align:center;\">(2)</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">V.R</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">R<hr size=\"1\" />r</td><td style=\"text-align:center;\">----------------</td><td style=\"text-align:center;\">(3)</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Efficiency</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">[</td><td style=\"text-align:center;\">(</td><td style=\"text-align:center;\">800<hr size=\"1\" />250</td><td style=\"text-align:center;\">)÷</td><td style=\"text-align:center;\">(</td><td style=\"text-align:center;\">800<hr size=\"1\" />200</td><td style=\"text-align:center;\">)</td><td style=\"text-align:center;\"></td></tr></table></div> <br/> Efficiency = [3.2 ÷ 4] 100 = 80% <br/> </div>", "topic": "SIMPLE MACHINES : EFFICIENCY OF MACHINES"}, {"id": "objective>Physics>2014>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A force of 500N is applied to a steel wire of cross-sectional area 0.2m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>, the tensile stress is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.0x10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.5x10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.5x10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.0x10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Tensile stress = force/area = 500/0.2 = 2.5x10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>.</div>", "topic": "ELASTICITY"}, {"id": "objective>Physics>2014>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  From the diagram above, the point that represents the elastic limit is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">R</div>", "<div style=\"font-family:Cambria;font-size:17px;\">S</div>", "<div style=\"font-family:Cambria;font-size:17px;\">T</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Q</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The elastic limit is represented by the point R. <br/>  <br/> The elastic limit is the maximum stress or force that can be applied to a material without causing permanent deformation. When the stress on the material is below this limit, it will return to its original shape and dimensions after the load is removed. However, if the applied stress exceeds the elastic limit, the material will undergo plastic deformation, resulting in permanent changes to its structure. The elastic limit is an important concept in materials science and engineering, as it helps determine the safe load-bearing capacity of materials in various applications.</div>", "topic": "ELASTICITY"}, {"id": "objective>Physics>2014>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The small droplets of water that form on the grass in the early hours of the morning is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mist</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dew</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fog</div>", "<div style=\"font-family:Cambria;font-size:17px;\">haul</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Dew is the small droplets of water that settles on grasses in the open atmosphere in the early hours of the day.</div>", "topic": "VAPOURS : DEW POINT, HUMIDITY AND RELATIVE HUMIDITY"}, {"id": "objective>Physics>2014>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is the equivalent of 20K in Celsius scale?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">68°C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">36°C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">-20°C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">-253°C</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Kelvin scale is an absolute temperature scale starting at absolute zero, the point at which all molecular motion ceases. To convert from Kelvin to Celsius, subtract 273.15 from the Kelvin temperature. Therefore, 20K - 273.15 = -253.15°C. The closest option is -253°C, which is option 4.</div>", "topic": "TEMPERATURE AND ITS MEASUREMENT : CONVERSION"}, {"id": "objective>Physics>2014>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A glass bottle of initial volume 2 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span> cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> is heated from 20°C to 50°C. If the linear expansivity of glass is 9 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span>K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>, the volume of the bottle at 50°C is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">20 008.1cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">20013.5cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">20016.2cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">20005.4cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Initial Volume, V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 2 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span>cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> Initial temperature, θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 20°C <br/> Final temperature, θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 50°C <br/> Linear expansivity, α = 9 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span>k<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> Final volume, V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = ? <br/> Recall: <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">γ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">ΔV<hr size=\"1\" />V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>Δθ</td><td style=\"text-align:center;\">--------------</td><td style=\"text-align:center;\">(1)</td></tr></table></div> <br/> ΔV = V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> - V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> ----------------- (2) <br/> γ = 3α ---------------- (3) <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">3α</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>-V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>Δθ</td><td style=\"text-align:center;\">-----------------</td><td style=\"text-align:center;\">(4)</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">3</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">9</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>-V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />2×10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span>(30)</td></tr></table></div> <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> - V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 27 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span> × 60 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span> <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> - V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 1620 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> = 16.2 <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> - 2 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span> = 16.2 <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 16.2 + 20,000 = 20,016.2 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "topic": "THERMAL EXPANSION : SOLIDS"}, {"id": "objective>Physics>2014>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The equation P<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">a</span>V<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">b</span>T<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">c</span> = constant reduces to Charles law if</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a = 0, b = 1 and c = 1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a = 0, b = 1 and c = -1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a = 1, b = 1 and c = 0</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a = 1, b = 0 and c = -1</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">P<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">a</span>V<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">b</span>T<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">c</span> = constant reduces to Charles law if a = 0, b = 1 and c = -1</div>", "topic": "GAS LAWS"}, {"id": "objective>Physics>2014>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The quantity of heat needed to raise the temperature of a body by 1K is the body's</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">specific heat capacity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">latent heat of fusion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">heat capacity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">internal energy</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The quantity of heat needed to raise the temperature of a body by 1K is defined as the heat capacity of the body. Specific heat capacity is the heat required to raise the temperature of 1 kg of the substance by 1K. Latent heat of fusion is the heat required to change a substance from solid to liquid state without change in temperature. Internal energy is the total energy stored in the substance. Therefore, the correct answer is heat capacity.</div>", "topic": "QUANTITY OF HEAT : HEAT CAPACITY AND SPECIFIC HEAT CAPACITY"}, {"id": "objective>Physics>2014>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The melting point of a substance is equivalent to its</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">liquidification temperature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">solidification pressures</div>", "<div style=\"font-family:Cambria;font-size:17px;\">vapour pressure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">solidification temperature</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The melting point of a substance is equivalent to its D) solidification temperature. <br/>  <br/> The melting point and solidification point of a substance are the same temperature. At this temperature, the substance exists in both the solid and liquid phases. When heat is added to a solid at its melting point, the solid will begin to melt and turn into a liquid. Conversely, when heat is removed from a liquid at its solidification point, the liquid will begin to solidify and turn into a solid.</div>", "topic": "CHANGE OF STATE : MELTING"}, {"id": "objective>Physics>2014>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The temperature at which the water vapour present in the air is just sufficient to saturate the air is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">saturation point</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dew point</div>", "<div style=\"font-family:Cambria;font-size:17px;\">boiling point</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ice point</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The temperature at which the water vapour present in the air is just sufficient to saturate the air is \"DEW POINT\"</div>", "topic": "VAPOURS : DEW POINT, HUMIDITY AND RELATIVE HUMIDITY"}, {"id": "objective>Physics>2014>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Heat transfer by convection in a liquid is due to the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">variation of density of the liquid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">expansion of the liquid as it is heated</div>", "<div style=\"font-family:Cambria;font-size:17px;\">latent heat of vaporization of the liquid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increased vibration of the molecules of the liquid about their mean position</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Heat transfer by convection in a liquid is due to the variation of density of the liquid. When a liquid is heated, the part of the liquid in contact with the heat source becomes less dense and rises. The cooler, denser part of the liquid then moves to replace it, creating a convection current. Therefore, option 1 is correct.</div>", "topic": "HEAT TRANSFER"}, {"id": "objective>Physics>2014>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The distance between two successive crests of a wave is 15cm and the velocity 300ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>. Calculate the frequency.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2.0x10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>Hz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.5x10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>Hz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.0x10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>Hz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.5x10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>Hz</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Distance between two successive crests (wavelength), λ = 15cm = 0.15m <br/> Velocity, V = 300ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> Frequency, f = ? <br/> Recall: <br/>  Velocity, V = fλ  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Frequency,</td><td style=\"text-align:center;\">f</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">v<hr size=\"1\" />λ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">300<hr size=\"1\" />0.15</td><td style=\"text-align:center;\"> <br/> </td></tr></table></div>f = 2.0x10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>Hz.</div>", "topic": "WAVES : PRODUCTION AND PROPAGATION"}, {"id": "objective>Physics>2014>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A boy receives the echo of his clap reflected by a nearby hill 0.8s later. <br/>   <br/> How far is he from the hill? <br/> [speed of sound in air 340 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">136m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">264m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">528m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">66m\t\t\t\t\t</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">This is a question which tests the concept of echo. <br/> <img src=\"2014/2.png\" style=\"position:relative;max-width:100%;\"/> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Velocity</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">total distance<hr size=\"1\" />time</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2x<hr size=\"1\" />t</td><td style=\"text-align:center;\">-------------</td><td style=\"text-align:center;\">(i)</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">340</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2x<hr size=\"1\" />0.8</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">340 × 0.8<hr size=\"1\" />2</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">170</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">0.8</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">136m</td></tr></table></div></div>", "topic": "PROPAGATION OF SOUND WAVES : ECHO AND REVERBERATION"}, {"id": "objective>Physics>2014>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  The diagram above shows a stationary wave of wavelength 40 cm in a closed tube. The length L of the resonating air column is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">20cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">30cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">40cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10cm</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: the diagram in the question <br/> <img src=\"2014/3.png\" style=\"position:relative;max-width:100%;\"/> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">L</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3(40)<hr size=\"1\" />4</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">30cm</td></tr></table></div></div>", "topic": "CHARACTERISTICS OF SOUND WAVES : RESONANCE"}, {"id": "objective>Physics>2014>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An object is placed 10m from a pinhole camera of length 25cm. Calculate the linear magnification.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2.5x10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.5x10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.5x10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.5x10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Object distance, U = 10m <br/> Image distance, V = 25cm = 0.25m <br/> Linear magnification, m = ? <br/> Recall: <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">m</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">V<hr size=\"1\" />U</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.25<hr size=\"1\" />10</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.025</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2.5</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></td></tr></table></div></div>", "topic": "LIGHT ENERGY : PROPAGATION OF LIGHT"}, {"id": "objective>Physics>2014>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The focal length of a concave mirror is 2.0 cm. If an object is placed 8.0 cm from it, the image is at</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2.3cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.5cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.7cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.0cm</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Focal length, f = 2.0cm <br/> Object distance, U = 8.0cm <br/> Image distance, V = ? <br/> Recall: <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />f</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />v</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />u</td><td style=\"text-align:center;\"></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">1<hr size=\"1\" />v</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />f</td><td style=\"text-align:center;\">-</td><td style=\"text-align:center;\">1<hr size=\"1\" />u</td><td style=\"text-align:center;\"></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />v</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">-1<hr size=\"1\" />8</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />v</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">4-1<hr size=\"1\" />8</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />v</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3<hr size=\"1\" />8</td><td style=\"text-align:center;\"></td></tr></table></div> <br/> 8 = 3v <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">v</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">8<hr size=\"1\" />3</td><td style=\"text-align:center;\"></td></tr></table></div> <br/> v = 2.7cm.</div>", "topic": "REFLECTION OF LIGHT AT PLANE AND CURVED SURFACES : USE OF THE MIRROR FORMULA"}, {"id": "objective>Physics>2014>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a compound microscope, the objective and the eye piece focal lengths are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Short</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the same</div>", "<div style=\"font-family:Cambria;font-size:17px;\">at infinity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">long</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a compound microscope, the objective and the eye piece focal lengths are short. The objective lens of a compound microscope is small and has a short focal length. This is to allow a greater amount of light to enter from the object being viewed. The eyepiece also has a short focal length to magnify the image formed by the objective lens.</div>", "topic": "OPTICAL INSTRUMENTS"}, {"id": "objective>Physics>2014>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When a telescope is in normal use, the final image is at</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the radius of curvature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the near point</div>", "<div style=\"font-family:Cambria;font-size:17px;\">infinity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the focus</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When a telescope is in normal use, the final image is at infinity. This is because the telescope is designed to view distant objects. The light rays from a distant object are parallel and when these parallel rays are refracted through the telescope's objective lens, they converge at the focal point. The eyepiece lens then takes this image and refracts the light rays so they are parallel again, creating an image at infinity for the viewer.</div>", "topic": "OPTICAL INSTRUMENTS"}, {"id": "objective>Physics>2014>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When a negatively-charged rod is brought near the cap of a charged gold leaf electroscope which has positive charges, the leaf</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">collapses and diverges again</div>", "<div style=\"font-family:Cambria;font-size:17px;\">diverges</div>", "<div style=\"font-family:Cambria;font-size:17px;\">remains the same</div>", "<div style=\"font-family:Cambria;font-size:17px;\">collapses</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When a negatively-charged rod is brought near the cap of a charged gold leaf electroscope which has positive charges, the leaf collapses.</div>", "topic": "ELECTROSTATICS : ELECTROSCOPE"}, {"id": "objective>Physics>2014>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What charge is stored in a 0.1 F capacitor when a 10V supply is connected across it?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5C</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Capacitance, C = 0.1F <br/> Voltage, V = 10V <br/> Charge, Q = ? <br/> Recall: Q = CV <br/> Q = 0.1 × 10 = 1C</div>", "topic": "CAPACITORS : CAPACITANCE OF A CAPACITORS"}, {"id": "objective>Physics>2014>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  Calculate the effective capacitance of the circuit above.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2 μf</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3 μf</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4 μf</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1 μf</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: the diagram in the question <br/> <img src=\"2014/4.png\" style=\"position:relative;max-width:100%;\"/> <br/> N.B: When capacitors are connected in parallel, the effective capacitance is given as the sum of all the individual capacitances. <br/> The diagram becomes <br/> <img src=\"2014/5.png\" style=\"position:relative;max-width:100%;\"/> <br/> N.B: When capacitors are connected in series, the reciprocal of the effective capacitance is equal to the sum of the reciprocals of the individual capacitances. <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />6</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />3</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1+3+2<hr size=\"1\" />6</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">6<hr size=\"1\" />6</td></tr></table></div> <br/> C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span> = 1.0μf</div>", "topic": "CAPACITORS : CAPACITORS IN SERIES AND PARALLEL"}, {"id": "objective>Physics>2014>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The maximum power transfer occurs in a cell when the external resistance is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">greater than the internal resistance of the cell</div>", "<div style=\"font-family:Cambria;font-size:17px;\">less than the internal resistance of the cell </div>", "<div style=\"font-family:Cambria;font-size:17px;\">twice the internal resistance of the cell </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the same as the internal resistance of the cell</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The maximum power transfer occurs in a cell when the external resistance is the same as the internal resistance of the cell.</div>", "topic": "ELECTRIC CELLS"}, {"id": "objective>Physics>2014>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If a metal wire 4 m long and cross-sectional area 0.8 mm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> has a resistance of 6Ω, find the resistivity of the wire.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.2x10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span>Ωm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.2x10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span>Ωm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5.3x10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-7</span>Ωm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.0x10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span>Ωm</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Length, L = 4.0m <br/> Cross-sectional Area, A = 0.8mm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> <br/> Resistance, R = 6Ω <br/> Resistivity, ρ = ? <br/> Recall: <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">ρ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">RA<hr size=\"1\" />L</td><td style=\"text-align:center;\">------------</td><td style=\"text-align:center;\">*</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">ρ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">6 × 0.8 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>×10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span><hr size=\"1\" />4</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1.2</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span>Ωm</td></tr></table></div></div>", "topic": "CURRENT ELECTRICITY: RESISTIVITY AND CONDUCTIVITY"}, {"id": "objective>Physics>2014>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A circuit has a resistance of 200Ω. The resistance of the circuit can be reduced to 120ω when</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a 150Ω resistor is connected to it in parallel</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a 240Ω resistor is connected to it in series</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a 300Ω resistor is connected to it in parallel</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an 80Ω resistor is connected to it in series</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The resistance of a circuit can be reduced by connecting a resistor in parallel. The formula for total resistance when resistors are connected in parallel is given by 1/Rt = 1/R1 + 1/R2 + ... + 1/Rn. If we substitute Rt = 120Ω and R1 = 200Ω into the formula, we can solve for R2, which gives us R2 = 300Ω.</div>", "topic": "CURRENT ELECTRICITY : RESISTANCE IN SERIES AND IN PARALLEL"}, {"id": "objective>Physics>2014>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">PHCN measures its electrical energy in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Wh</div>", "<div style=\"font-family:Cambria;font-size:17px;\">J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">W</div>", "<div style=\"font-family:Cambria;font-size:17px;\">kWh</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Power Holding Company of Nigeria (PHCN) measures its electrical energy in kilowatt-hours (kWh). This is because the kilowatt-hour is a unit of energy equivalent to one kilowatt (1 kW) of power expended for one hour of time.</div>", "topic": "ELECTRICAL ENERGY AND POWER : COMMERCIAL UNIT OF ELECTRIC ENERGY AND POWER"}, {"id": "objective>Physics>2014>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is the best method of demagnetizing a steel bar magnet?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Rough-handling it</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Solenoid method</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hammering</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Beating it</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Solenoid method. It involves inserting the magnet into a coil of conducting wire and passing current through it.</div>", "topic": "MAGNETS AND MAGNETIC FIELDS"}, {"id": "objective>Physics>2014>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The magnitude of the angle of dip at the equator</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">90°</div>", "<div style=\"font-family:Cambria;font-size:17px;\">180°</div>", "<div style=\"font-family:Cambria;font-size:17px;\">360°</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0°</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The angle of dip, also known as magnetic inclination, is the angle made with the horizontal by the Earth's magnetic field lines. This angle varies at different points on the Earth's surface. At the equator, the magnetic field is perfectly horizontal, hence the angle of dip is 0°.</div>", "topic": "MAGNETS AND MAGNETIC FIELDS : EARTH’S MAGNETIC FIELD"}, {"id": "objective>Physics>2014>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><p style=\"padding: 3px;\">Use the diagram below to answer the question that follows</p>  <br/>  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The diagram above is that of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a step-down transformer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an auto transformer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an oil transformer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a step-up transformer</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is a step-up transformer because the number of turns in the secondary is higher than that of the primary.</div>", "topic": "ELECTROMAGNETIC INDUCTION : TRANSFORMERS"}, {"id": "objective>Physics>2014>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">Use the diagram below to answer the question that follows</p>  <br/>  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The electromotive force in the secondary winding is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">reducing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">stabilizing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">varying</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increasing</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The electromotive force in the secondary winding is increasing.</div>", "topic": "ELECTROMAGNETIC INDUCTION : TRANSFORMERS"}, {"id": "objective>Physics>2014>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What type of reaction is represented by the equation <span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>X + <span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>X ↔ <span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>Y + <span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">1</span>n  + energy?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Fission</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Chain</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ionization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fusion</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The reaction is fusion because it involves two smaller nuclei joining to form a larger nucleus with the release of neutrons.</div>", "topic": "ELEMENTARY MODERN PHYSICS : FUSION AND FISSION"}, {"id": "objective>Physics>2014>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When an atom undergoes a beta decay, the atomic number of the nucleus</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increases by one</div>", "<div style=\"font-family:Cambria;font-size:17px;\">becomes zero</div>", "<div style=\"font-family:Cambria;font-size:17px;\">remains unchanged</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decreases by one</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Beta decay is a type of radioactive decay in which a beta particle (an electron or a positron) is emitted. In the case of beta minus decay (electron emission), a neutron in the nucleus is transformed into a proton, an electron, and an electron antineutrino. This increases the atomic number by one because the number of protons in the nucleus increases by one.</div>", "topic": "ELEMENTARY MODERN PHYSICS : ALPHA, BETA AND GAMMA RAYS"}, {"id": "objective>Physics>2014>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Calculate the mass of the copper deposited during electrolysis when a current of 4A passes through a copper salt for 2 hours. <br/>  [ece of copper z = 3.3 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-7</span>kgC<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">9.5x10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>kg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.9x10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>kg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.9x10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span>kg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">9.5x10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-7</span>kg</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> mass(m) = ? <br/> Current. I = 4A <br/> time, t = 2 hrs = 2 × 3600s = 7200s <br/> Electrochemical Equivalent, Z = 3.3 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-7</span>kgc<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> Recall: m = ZIt -------------- * <br/> m = 3.3 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-7</span> × 4 × 7200 <br/> m = 9.504 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span> × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-7</span> <br/> m = 9.504 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>kg</div>", "topic": "CURRENT ELECTRICITY: ELECTROLYSIS"}, {"id": "objective>Physics>2014>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which gas produces a pink coloured light in a discharge tube?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Air</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Neon</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mercury</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Argon</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When an electric discharge passes through a gas at low pressure, it emits characteristic light. Different gases produce different colors: <br/>  <br/> Neon (Ne) → Pinkish-red or orange glow (commonly used in neon signs). <br/>  <br/> Mercury (Hg) → Bluish glow (used in fluorescent lamps). <br/>  <br/> Argon (Ar) → Pale blue/violet glow (used in some light bulbs). <br/>  <br/> Air → No distinct color, as it is a mixture of gases.</div>", "topic": "CONDUCTION OF ELECTRICITY THROUGH : GASES"}, {"id": "objective>Physics>2014>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">210</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">82</span>Pb decays to <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">206</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">80</span>Pb, it emits</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">one beta particle</div>", "<div style=\"font-family:Cambria;font-size:17px;\">one alpha and one beta particle</div>", "<div style=\"font-family:Cambria;font-size:17px;\">two alpha and two beta particles</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an alpha particle</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The decay of <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">210</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">82</span>Pb to <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">206</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">80</span>Pb involves the emission of an alpha particle. An alpha particle consists of 2 protons and 2 neutrons, which means the atomic number decreases by 2 and the atomic mass decreases by 4. This is exactly what happens in the given decay process, hence the correct answer is option 4.</div>", "topic": "ELEMENTARY MODERN PHYSICS : ALPHA, BETA AND GAMMA RAYS"}, {"id": "objective>Physics>2014>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a common emitter configuration, the output voltage is through the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">collector</div>", "<div style=\"font-family:Cambria;font-size:17px;\">emitter</div>", "<div style=\"font-family:Cambria;font-size:17px;\">resistor</div>", "<div style=\"font-family:Cambria;font-size:17px;\">base</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a common emitter configuration, the output voltage is through the collector. <br/>  <br/> In common emitter configuration, input voltage (VBE) is applied between base and emitter terminals, output voltage VCE is applied between emitter and collector while Emitter is connected to both input and output. Base is the input terminal, collector is the output terminal and emitter is the common terminal for both input and output.</div>", "topic": "INTRODUCTORY ELECTRONICS : TRANSISTORS"}, {"id": "objective>Physics>2014>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the graphs below shows the characteristics of an I-V transistor?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"2014/2014img9.png\" style=\"position:relative;max-width:100%;\"/>  <br/>  It is the I-V characteristics of a transistor.</div>", "topic": "INTRODUCTORY ELECTRONICS : TRANSISTORS"}];
